def multi_step_checkout(cart_items, discount_code, user, payment_info):
    # Step 1: Validate cart items
    validated_cart = validate_cart_items(cart_items)
    if not validated_cart:
        return {"error": "Invalid cart items"}
    
    # Step 2: Apply discount codes
    discounted_total = apply_discount_code(validated_cart, discount_code, user)
    if isinstance(discounted_total, dict) and "error" in discounted_total:
        return discounted_total
    
    # Step 3: Calculate tax
    tax_amount = calculate_tax(discounted_total, user)
    total_with_tax = discounted_total + tax_amount
    
    # Step 4: Process payment
    payment_result = process_payment(total_with_tax, payment_info)
    if not payment_result["success"]:
        return {"error": "Payment failed", "details": payment_result["error"]}
    
    # Step 5: Create order record
    order_record = create_order_record(validated_cart, discount_code, user, total_with_tax, tax_amount, payment_result["transaction_id"])
    
    return {
        "success": True,
        "order_id": order_record["order_id"],
        "total": total_with_tax,
        "tax": tax_amount,
        "transaction_id": payment_result["transaction_id"]
    }

def validate_cart_items(cart_items):
    if not cart_items:
        return False
    
    for item in cart_items:
        if not item.get("product_id") or not item.get("quantity") or item.get("quantity", 0) <= 0:
            return False
        if item.get("price", 0) < 0:
            return False
    
    return cart_items

def apply_discount_code(cart_items, discount_code, user):
    if not discount_code:
        return sum(item.get("price", 0) * item.get("quantity", 0) for item in cart_items)
    
    valid_codes = {
        "SAVE10": {"discount": 0.1, "admin_only": False, "tier_required": None},
        "SAVE20": {"discount": 0.2, "admin_only": False, "tier_required": "premium"},
        "SAVE30": {"discount": 0.3, "admin_only": True, "tier_required": None},
        "SAVE50": {"discount": 0.5, "admin_only": True, "tier_required": "vip"}
    }
    
    if discount_code not in valid_codes:
        return {"error": "Invalid discount code"}
    
    code_info = valid_codes[discount_code]
    
    if code_info["admin_only"] and not user.get("is_admin"):
        return {"error": "Admin only discount code"}
    
    if code_info["tier_required"] and user.get("tier") != code_info["tier_required"]:
        return {"error": f"Tier {code_info['tier_required']} required for this discount"}
    
    total = sum(item.get("price", 0) * item.get("quantity", 0) for item in cart_items)
    discounted_total = total * (1 - code_info["discount"])
    
    return discounted_total

def calculate_tax(total, user):
    tax_rates = {
        "us": 0.08,
        "uk": 0.2,
        "ca": 0.05,
        "default": 0.0
    }
    
    country = user.get("country", "default")
    tax_rate = tax_rates.get(country, tax_rates["default"])
    
    return total * tax_rate

def process_payment(total, payment_info):
    if not payment_info.get("card_number") or not payment_info.get("expiry_date") or not payment_info.get("cvv"):
        return {"success": False, "error": "Incomplete payment information"}
    
    # Simulate payment processing
    import random
    if random.random() > 0.1:  # 90% success rate
        return {
            "success": True,
            "transaction_id": f"txn_{random.randint(100000, 999999)}"
        }
    else:
        return {
            "success": False,
            "error": "Payment declined by processor"
        }

def create_order_record(cart_items, discount_code, user, total, tax_amount, transaction_id):
    import uuid
    order_id = str(uuid.uuid4())
    
    order_record = {
        "order_id": order_id,
        "user_id": user.get("user_id"),
        "items": cart_items,
        "discount_code": discount_code,
        "total": total,
        "tax_amount": tax_amount,
        "transaction_id": transaction_id,
        "status": "completed",
        "created_at": "2023-01-01T00:00:00Z"
    }
    
    # In a real implementation, this would save to a database
    return order_record